namespace sv_6c82c5fc1812401a8d47e5a08d98c092.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_6c82c5fc1812401a8d47e5a08d98c092.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="d-flex flex-row gap-4">
    @* ─── Left Sidebar (Filters) ─── *@
    <div style="min-width:250px; flex:0 0 25%;">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Category checkboxes *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading categories…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small">Min Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="minPrice" />
                </div>
                <div class="mb-2">
                    <label class="form-label small">Max Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="maxPrice" />
                </div>

                <hr />

                @* In Stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ─── Main Content ─── *@
    <div style="flex:1 1 75%; min-width:0;">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height:300px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found matching your criteria.
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 fw-semibold">Sort by:</label>
                    <select class="form-select form-select-sm" style="width:auto;" @bind="sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted">
                    Showing @(firstItem)–@(lastItem) of @(result.TotalCount) products
                </span>
            </div>

            @* Product Grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-4">
                @foreach (var product in result.Items)
                {
                    <div class="col">
                        <div class="card h-100 product-card" @onclick="() => OnProductSelected(product.Id)"
                             style="cursor:pointer;" role="button">
                            <div class="bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
                                 style="height:180px;" title="@product.Name">
                                <span class="text-muted">@product.Name</span>
                            </div>
                            <div class="card-body d-flex flex-column">
                                <h6 class="card-title">@product.Name</h6>
                                <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                <p class="card-text mb-2">
                                    @GetStarRating(product.Rating)
                                </p>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <button class="btn btn-sm btn-success mt-auto"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => { }" @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    </div>
                }
            </div>

            @* Pagination *@
            <nav aria-label="Product pagination">
                <ul class="pagination justify-content-center">
                    <li class="page-item @(currentPage <= 1 ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                disabled="@(currentPage <= 1)">Previous</button>
                    </li>
                    @for (int i = 1; i <= totalPages; i++)
                    {
                        var page = i;
                        <li class="page-item @(page == currentPage ? "active" : "")">
                            <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                        </li>
                    }
                    <li class="page-item @(currentPage >= totalPages ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                disabled="@(currentPage >= totalPages)">Next</button>
                    </li>
                </ul>
            </nav>
        }
    </div>
</div>

@code {
    [Parameter] public EventCallback<int> OnProductClick { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int totalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    private int firstItem => result is null ? 0 : (result.Page - 1) * result.PageSize + 1;
    private int lastItem => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialData();
    }

    private async Task LoadInitialData()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = SearchProducts();

            categories = await categoriesTask;
            result = await productsTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            result = await SearchProducts();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private Task<PagedResult<Product>> SearchProducts()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );

        return ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;
        await LoadProducts();
    }

    private async Task OnProductSelected(int productId)
    {
        if (OnProductClick.HasDelegate)
        {
            await OnProductClick.InvokeAsync(productId);
        }
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

